import{_ as s,c as a,a as e,o as t}from"./app-DfFNXaa-.js";const p={};function o(c,n){return t(),a("div",null,[...n[0]||(n[0]=[e(`<h1 id="tantivy-tokenizer" tabindex="-1"><a class="header-anchor" href="#tantivy-tokenizer"><span>Tantivy - Tokenizer</span></a></h1><p>Created by: Mr Dk.</p><p>Co-authored by: Claude Opus 4.6</p><p>2026 / 06 / 05 23:00</p><p>Hangzhou, Zhejiang, China</p><hr><h2 id="背景" tabindex="-1"><a class="header-anchor" href="#背景"><span>背景</span></a></h2><p>在全文搜索里，原始文本通常不能直接进入倒排索引。索引真正关心的是一个个独立的词项（term），所以写入索引之前，需要先把文本切成一串 token。这个过程就是 <strong>分词（tokenization）</strong>。</p><p>分词看起来只是&quot;切字符串&quot;，但它会直接影响搜索效果。最简单的做法是按空格切分；实际场景里还会叠加很多处理：把大写转成小写，让搜索对大小写不敏感；去掉 &quot;the&quot;、&quot;is&quot; 这类停用词；把 &quot;running&quot; 归一化成 &quot;run&quot; 这样的词干；对于中文这类没有天然空格分隔的语言，还需要基于词典或模型做分词。</p><p>Tantivy 把这件事抽象成一条流水线：前面是一个基础分词器（Tokenizer），后面可以接若干个过滤器（Token Filter）。Tokenizer 负责把文本切开，Filter 负责继续加工这些 token。每一层都只做一件事，因此可以自由组合、替换。Tantivy 内置了一批常用实现，也把核心接口做成公开 trait，方便用户和社区扩展。</p><h2 id="分词流水线-整体结构" tabindex="-1"><a class="header-anchor" href="#分词流水线-整体结构"><span>分词流水线：整体结构</span></a></h2><p>先看一段文本从输入到最终写入倒排索引的大致路径：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">原始文本 &quot;Hello, the WORLD! Welcome here.&quot;</span>
<span class="line">  │</span>
<span class="line">  ▼</span>
<span class="line">┌───────────────────────────┐</span>
<span class="line">│  Tokenizer                │  切分文本 → 产生 token 流</span>
<span class="line">│  (e.g. SimpleTokenizer)   │</span>
<span class="line">└───────────────────────────┘</span>
<span class="line">  │  &quot;Hello&quot; → &quot;the&quot; → &quot;WORLD&quot; → &quot;Welcome&quot; → &quot;here&quot;</span>
<span class="line">  ▼</span>
<span class="line">┌───────────────────────────┐</span>
<span class="line">│  TokenFilter 1            │  变换每个 token（转小写）</span>
<span class="line">│  (e.g. LowerCaser)        │</span>
<span class="line">└───────────────────────────┘</span>
<span class="line">  │  &quot;hello&quot; → &quot;the&quot; → &quot;world&quot; → &quot;welcome&quot; → &quot;here&quot;</span>
<span class="line">  ▼</span>
<span class="line">┌───────────────────────────┐</span>
<span class="line">│  TokenFilter 2            │  过滤掉某些 token（去停用词）</span>
<span class="line">│  (e.g. StopWordFilter)    │</span>
<span class="line">└───────────────────────────┘</span>
<span class="line">  │  &quot;hello&quot; → &quot;world&quot; → &quot;welcome&quot; → &quot;here&quot;</span>
<span class="line">  ▼</span>
<span class="line">写入倒排索引</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这条链路里有三个最核心的抽象：</p><ul><li><code>Tokenizer</code>：流水线的起点，负责把原始文本切成 token。</li><li><code>TokenStream</code>：Tokenizer 的输出，本质上是一个可迭代的 token 流。调用方通过 <code>advance()</code> 推进到下一个 token，再用 <code>token()</code> 读取当前 token 的内容。</li><li><code>TokenFilter</code>：流水线的中间节点，采用装饰器模式。它接收一个上游 Tokenizer，包装后产出一个新的 Tokenizer：新的 <code>TokenStream</code> 在迭代时会对上游 token 做变换，比如转小写；也可以做过滤，比如跳过停用词。</li></ul><h3 id="组装流水线-textanalyzer" tabindex="-1"><a class="header-anchor" href="#组装流水线-textanalyzer"><span>组装流水线：TextAnalyzer</span></a></h3><p>Tantivy 用 <code>TextAnalyzer</code> 表示一条完整的分析流水线。它的 builder 接收一个基础 Tokenizer，然后依次在链条上追加若干 TokenFilter：</p><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token keyword">let</span> analyzer <span class="token operator">=</span> <span class="token class-name">TextAnalyzer</span><span class="token punctuation">::</span><span class="token function">builder</span><span class="token punctuation">(</span><span class="token class-name">SimpleTokenizer</span><span class="token punctuation">::</span><span class="token function">default</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">filter</span><span class="token punctuation">(</span><span class="token class-name">RemoveLongFilter</span><span class="token punctuation">::</span><span class="token function">limit</span><span class="token punctuation">(</span><span class="token number">40</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">filter</span><span class="token punctuation">(</span><span class="token class-name">LowerCaser</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">filter</span><span class="token punctuation">(</span><span class="token class-name">Stemmer</span><span class="token punctuation">::</span><span class="token function">new</span><span class="token punctuation">(</span><span class="token class-name">Language</span><span class="token punctuation">::</span><span class="token class-name">English</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>每调用一次 <code>.filter()</code>，都会通过 <code>TokenFilter::transform()</code> 把当前 Tokenizer 再包一层，于是形成一条嵌套的类型链。最后 <code>.build()</code> 通过 <code>BoxableTokenizer</code> 做类型擦除，把整条流水线封装成统一的 <code>TextAnalyzer</code> 类型。</p><h3 id="注册与查找-tokenizermanager" tabindex="-1"><a class="header-anchor" href="#注册与查找-tokenizermanager"><span>注册与查找：TokenizerManager</span></a></h3><p><code>TokenizerManager</code> 可以理解为一个线程安全的 <code>HashMap&lt;String, TextAnalyzer&gt;</code>。每个索引实例都有自己的 manager，所以不同索引可以注册不同的分析器。使用时通过字符串名字注册和查找：</p><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token comment">// 注册自定义 tokenizer</span></span>
<span class="line">index<span class="token punctuation">.</span><span class="token function">tokenizers</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">register</span><span class="token punctuation">(</span><span class="token string">&quot;my_analyzer&quot;</span><span class="token punctuation">,</span> analyzer<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 在 Schema 中引用</span></span>
<span class="line"><span class="token keyword">let</span> text_field_indexing <span class="token operator">=</span> <span class="token class-name">TextFieldIndexing</span><span class="token punctuation">::</span><span class="token function">default</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">set_tokenizer</span><span class="token punctuation">(</span><span class="token string">&quot;my_analyzer&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">set_index_option</span><span class="token punctuation">(</span><span class="token class-name">IndexRecordOption</span><span class="token punctuation">::</span><span class="token class-name">WithFreqsAndPositions</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>默认构造的 <code>TokenizerManager</code> 会预先注册四个内置分析器：<code>raw</code>、<code>default</code>、<code>en_stem</code>、<code>whitespace</code>。这些名字可以在 schema 中直接引用，不需要用户额外注册。</p><h2 id="接口定义" tabindex="-1"><a class="header-anchor" href="#接口定义"><span>接口定义</span></a></h2><p>Tantivy 把分词相关的核心接口放在独立的 <code>tantivy-tokenizer-api</code> crate 中。这样第三方实现自定义分词器时，只需要依赖这个很轻的 API crate，不必把完整的 tantivy 拉进来。</p><h3 id="token" tabindex="-1"><a class="header-anchor" href="#token"><span>Token</span></a></h3><p><code>Token</code> 是分词后的最小单元，里面除了文本本身，还保存了偏移和位置信息：</p><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token keyword">pub</span> <span class="token keyword">struct</span> <span class="token type-definition class-name">Token</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">pub</span> offset_from<span class="token punctuation">:</span> <span class="token keyword">usize</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">pub</span> offset_to<span class="token punctuation">:</span> <span class="token keyword">usize</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">pub</span> position<span class="token punctuation">:</span> <span class="token keyword">usize</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">pub</span> text<span class="token punctuation">:</span> <span class="token class-name">String</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">pub</span> position_length<span class="token punctuation">:</span> <span class="token keyword">usize</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>offset_from</code> / <code>offset_to</code>：token 在原始文本中的字节偏移范围，主要用于回溯原文，比如搜索结果高亮。</li><li><code>position</code>：token 在流中的序号。当 TokenFilter 跳过某些 token 时，position 会出现跳跃，搜索引擎可以据此知道两个 token 中间是否省略了词。这对短语查询很重要。</li><li><code>text</code>：token 的实际文本内容。</li><li><code>position_length</code>：这个 token 跨越了多少个 position，通常为 1。当多个词被折叠成一个 token 时，这个值会大于 1。比如把 &quot;New York City&quot; 折叠成 &quot;NYC&quot;，那么 &quot;NYC&quot; 的 <code>position_length</code> 就是 3，表示它覆盖了原本 3 个位置。短语匹配需要这个信息来正确计算 token 之间的距离。</li></ul><h3 id="tokenizer-trait" tabindex="-1"><a class="header-anchor" href="#tokenizer-trait"><span>Tokenizer trait</span></a></h3><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token keyword">pub</span> <span class="token keyword">trait</span> <span class="token type-definition class-name">Tokenizer</span><span class="token punctuation">:</span> <span class="token lifetime-annotation symbol">&#39;static</span> <span class="token operator">+</span> <span class="token class-name">Clone</span> <span class="token operator">+</span> <span class="token class-name">Send</span> <span class="token operator">+</span> <span class="token class-name">Sync</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">type</span> <span class="token type-definition class-name">TokenStream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span><span class="token punctuation">:</span> <span class="token class-name">TokenStream</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">fn</span> <span class="token function-definition function">token_stream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span><span class="token punctuation">(</span><span class="token operator">&amp;</span><span class="token lifetime-annotation symbol">&#39;a</span> <span class="token keyword">mut</span> <span class="token keyword">self</span><span class="token punctuation">,</span> text<span class="token punctuation">:</span> <span class="token operator">&amp;</span><span class="token lifetime-annotation symbol">&#39;a</span> <span class="token keyword">str</span><span class="token punctuation">)</span> <span class="token punctuation">-&gt;</span> <span class="token keyword">Self</span><span class="token punctuation">::</span><span class="token class-name">TokenStream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>Tokenizer</code> 只有一个函数：<code>token_stream()</code>。它接收原始文本，返回一个 <code>TokenStream</code>。实际实现中，Tokenizer 通常会预先持有一个 <code>Token</code> 缓冲区，交给 <code>TokenStream</code> 反复复用，避免每产出一个 token 就分配一次内存。</p><h3 id="tokenstream-trait" tabindex="-1"><a class="header-anchor" href="#tokenstream-trait"><span>TokenStream trait</span></a></h3><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token keyword">pub</span> <span class="token keyword">trait</span> <span class="token type-definition class-name">TokenStream</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">fn</span> <span class="token function-definition function">advance</span><span class="token punctuation">(</span><span class="token operator">&amp;</span><span class="token keyword">mut</span> <span class="token keyword">self</span><span class="token punctuation">)</span> <span class="token punctuation">-&gt;</span> <span class="token keyword">bool</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">fn</span> <span class="token function-definition function">token</span><span class="token punctuation">(</span><span class="token operator">&amp;</span><span class="token keyword">self</span><span class="token punctuation">)</span> <span class="token punctuation">-&gt;</span> <span class="token operator">&amp;</span><span class="token class-name">Token</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">fn</span> <span class="token function-definition function">token_mut</span><span class="token punctuation">(</span><span class="token operator">&amp;</span><span class="token keyword">mut</span> <span class="token keyword">self</span><span class="token punctuation">)</span> <span class="token punctuation">-&gt;</span> <span class="token operator">&amp;</span><span class="token keyword">mut</span> <span class="token class-name">Token</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>TokenStream</code> 就是 token 流的迭代器：</p><ul><li><code>advance()</code>：推进到下一个 token，返回 <code>false</code> 表示流结束。</li><li><code>token()</code>：读取当前 token。</li><li><code>token_mut()</code>：获取当前 token 的可变引用，供 TokenFilter 在迭代过程中修改内容。</li></ul><h3 id="tokenfilter-trait" tabindex="-1"><a class="header-anchor" href="#tokenfilter-trait"><span>TokenFilter trait</span></a></h3><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token keyword">pub</span> <span class="token keyword">trait</span> <span class="token type-definition class-name">TokenFilter</span><span class="token punctuation">:</span> <span class="token lifetime-annotation symbol">&#39;static</span> <span class="token operator">+</span> <span class="token class-name">Send</span> <span class="token operator">+</span> <span class="token class-name">Sync</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">type</span> <span class="token type-definition class-name">Tokenizer</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token punctuation">:</span> <span class="token class-name">Tokenizer</span><span class="token operator">&gt;</span><span class="token punctuation">:</span> <span class="token class-name">Tokenizer</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">fn</span> <span class="token function-definition function">transform</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token punctuation">:</span> <span class="token class-name">Tokenizer</span><span class="token operator">&gt;</span><span class="token punctuation">(</span><span class="token keyword">self</span><span class="token punctuation">,</span> tokenizer<span class="token punctuation">:</span> <span class="token class-name">T</span><span class="token punctuation">)</span> <span class="token punctuation">-&gt;</span> <span class="token keyword">Self</span><span class="token punctuation">::</span><span class="token class-name">Tokenizer</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token operator">&gt;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>TokenFilter</code> 的核心就是 <code>transform()</code>：接收一个上游 <code>Tokenizer</code>，返回一个新的 <code>Tokenizer</code>。这正是装饰器模式的用法：每层过滤器包住上一层，最终形成嵌套结构。新 Tokenizer 产出的 token 流会先从上游拿 token，再做变换、过滤或扩展。</p><h2 id="实现-tokenizer-以-whitespacetokenizer-为例" tabindex="-1"><a class="header-anchor" href="#实现-tokenizer-以-whitespacetokenizer-为例"><span>实现 Tokenizer：以 WhitespaceTokenizer 为例</span></a></h2><p><code>WhitespaceTokenizer</code> 是最简单的内置分词器之一：它按 ASCII 空白字符切分文本，并保留标点符号。用它来看 <code>Tokenizer</code> 的实现方式比较合适，因为逻辑足够小，能把接口本身看清楚。</p><p>先看 Tokenizer 和 TokenStream 两个结构体：</p><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token attribute attr-name">#[derive(Clone, Default)]</span></span>
<span class="line"><span class="token keyword">pub</span> <span class="token keyword">struct</span> <span class="token type-definition class-name">WhitespaceTokenizer</span> <span class="token punctuation">{</span></span>
<span class="line">    token<span class="token punctuation">:</span> <span class="token class-name">Token</span><span class="token punctuation">,</span>  <span class="token comment">// 复用的 Token 缓冲区，避免反复分配</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">pub</span> <span class="token keyword">struct</span> <span class="token type-definition class-name">WhitespaceTokenStream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">    text<span class="token punctuation">:</span> <span class="token operator">&amp;</span><span class="token lifetime-annotation symbol">&#39;a</span> <span class="token keyword">str</span><span class="token punctuation">,</span>          <span class="token comment">// 原始文本</span></span>
<span class="line">    chars<span class="token punctuation">:</span> <span class="token class-name">CharIndices</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span><span class="token punctuation">,</span> <span class="token comment">// 字符迭代器，记录当前扫描位置</span></span>
<span class="line">    token<span class="token punctuation">:</span> <span class="token operator">&amp;</span><span class="token lifetime-annotation symbol">&#39;a</span> <span class="token keyword">mut</span> <span class="token class-name">Token</span><span class="token punctuation">,</span>   <span class="token comment">// 指向 Tokenizer 中复用的 Token</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>WhitespaceTokenizer</code> 内部预分配了一个 <code>Token</code>。每次调用 <code>token_stream()</code> 时，它先把这个 token 重置，然后借给 <code>WhitespaceTokenStream</code> 使用。这样整个分词过程里只有一个 <code>Token</code> 实例被反复写入，不会额外产生一堆临时对象。</p><p>实现 <code>Tokenizer</code> trait：</p><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token keyword">impl</span> <span class="token class-name">Tokenizer</span> <span class="token keyword">for</span> <span class="token class-name">WhitespaceTokenizer</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">type</span> <span class="token type-definition class-name">TokenStream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span> <span class="token operator">=</span> <span class="token class-name">WhitespaceTokenStream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">fn</span> <span class="token function-definition function">token_stream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span><span class="token punctuation">(</span><span class="token operator">&amp;</span><span class="token lifetime-annotation symbol">&#39;a</span> <span class="token keyword">mut</span> <span class="token keyword">self</span><span class="token punctuation">,</span> text<span class="token punctuation">:</span> <span class="token operator">&amp;</span><span class="token lifetime-annotation symbol">&#39;a</span> <span class="token keyword">str</span><span class="token punctuation">)</span> <span class="token punctuation">-&gt;</span> <span class="token class-name">WhitespaceTokenStream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">self</span><span class="token punctuation">.</span>token<span class="token punctuation">.</span><span class="token function">reset</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token class-name">WhitespaceTokenStream</span> <span class="token punctuation">{</span></span>
<span class="line">            text<span class="token punctuation">,</span></span>
<span class="line">            chars<span class="token punctuation">:</span> text<span class="token punctuation">.</span><span class="token function">char_indices</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">            token<span class="token punctuation">:</span> <span class="token operator">&amp;</span><span class="token keyword">mut</span> <span class="token keyword">self</span><span class="token punctuation">.</span>token<span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>接下来是 <code>TokenStream</code> 的实现。核心逻辑都在 <code>advance()</code> 里：逐字符扫描，先跳过空白字符；遇到非空白字符后，再找到当前 token 的结束位置，也就是下一个空白字符的位置。随后把这段文本的偏移和内容写入 <code>Token</code>，返回 <code>true</code>。如果字符迭代器已经耗尽，就返回 <code>false</code>，表示流结束。</p><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token keyword">impl</span> <span class="token class-name">TokenStream</span> <span class="token keyword">for</span> <span class="token class-name">WhitespaceTokenStream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;_</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">fn</span> <span class="token function-definition function">advance</span><span class="token punctuation">(</span><span class="token operator">&amp;</span><span class="token keyword">mut</span> <span class="token keyword">self</span><span class="token punctuation">)</span> <span class="token punctuation">-&gt;</span> <span class="token keyword">bool</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">self</span><span class="token punctuation">.</span>token<span class="token punctuation">.</span>text<span class="token punctuation">.</span><span class="token function">clear</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">self</span><span class="token punctuation">.</span>token<span class="token punctuation">.</span>position <span class="token operator">=</span> <span class="token keyword">self</span><span class="token punctuation">.</span>token<span class="token punctuation">.</span>position<span class="token punctuation">.</span><span class="token function">wrapping_add</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">while</span> <span class="token keyword">let</span> <span class="token class-name">Some</span><span class="token punctuation">(</span><span class="token punctuation">(</span>offset_from<span class="token punctuation">,</span> c<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token keyword">self</span><span class="token punctuation">.</span>chars<span class="token punctuation">.</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">if</span> <span class="token operator">!</span>c<span class="token punctuation">.</span><span class="token function">is_ascii_whitespace</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">                <span class="token keyword">let</span> offset_to <span class="token operator">=</span> <span class="token keyword">self</span><span class="token punctuation">.</span><span class="token function">search_token_end</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">                <span class="token keyword">self</span><span class="token punctuation">.</span>token<span class="token punctuation">.</span>offset_from <span class="token operator">=</span> offset_from<span class="token punctuation">;</span></span>
<span class="line">                <span class="token keyword">self</span><span class="token punctuation">.</span>token<span class="token punctuation">.</span>offset_to <span class="token operator">=</span> offset_to<span class="token punctuation">;</span></span>
<span class="line">                <span class="token keyword">self</span><span class="token punctuation">.</span>token<span class="token punctuation">.</span>text<span class="token punctuation">.</span><span class="token function">push_str</span><span class="token punctuation">(</span><span class="token operator">&amp;</span><span class="token keyword">self</span><span class="token punctuation">.</span>text<span class="token punctuation">[</span>offset_from<span class="token punctuation">..</span>offset_to<span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">                <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token punctuation">}</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">        <span class="token boolean">false</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token comment">// ...</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>以 <code>&quot;Hello, happy tax payer!&quot;</code> 为输入，<code>WhitespaceTokenizer</code> 会产出四个 token：</p><table><thead><tr><th>position</th><th>text</th><th>offset_from</th><th>offset_to</th></tr></thead><tbody><tr><td>0</td><td><code>Hello,</code></td><td>0</td><td>6</td></tr><tr><td>1</td><td><code>happy</code></td><td>7</td><td>12</td></tr><tr><td>2</td><td><code>tax</code></td><td>13</td><td>16</td></tr><tr><td>3</td><td><code>payer!</code></td><td>17</td><td>23</td></tr></tbody></table><p>注意 <code>Hello,</code> 和 <code>payer!</code> 都保留了标点。这正是 <code>WhitespaceTokenizer</code> 和 <code>SimpleTokenizer</code> 的区别：<code>SimpleTokenizer</code> 按 <code>!char.is_alphanumeric()</code> 分割，标点会被去除掉。</p><h2 id="实现-tokenfilter-以-stopwordfilter-为例" tabindex="-1"><a class="header-anchor" href="#实现-tokenfilter-以-stopwordfilter-为例"><span>实现 TokenFilter：以 StopWordFilter 为例</span></a></h2><p><code>StopWordFilter</code> 是一个典型的过滤型 TokenFilter。它维护一个停用词集合，在 token 流中跳过命中的 token。用它来看 TokenFilter 的装饰器模式会比较直观。</p><p>先看 <code>StopWordFilter</code> 本身，以及它对 <code>TokenFilter</code> 的实现：</p><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token attribute attr-name">#[derive(Clone)]</span></span>
<span class="line"><span class="token keyword">pub</span> <span class="token keyword">struct</span> <span class="token type-definition class-name">StopWordFilter</span> <span class="token punctuation">{</span></span>
<span class="line">    words<span class="token punctuation">:</span> <span class="token class-name">Arc</span><span class="token operator">&lt;</span><span class="token class-name">FxHashSet</span><span class="token operator">&lt;</span><span class="token class-name">String</span><span class="token operator">&gt;&gt;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">impl</span> <span class="token class-name">TokenFilter</span> <span class="token keyword">for</span> <span class="token class-name">StopWordFilter</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">type</span> <span class="token type-definition class-name">Tokenizer</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token punctuation">:</span> <span class="token class-name">Tokenizer</span><span class="token operator">&gt;</span> <span class="token operator">=</span> <span class="token class-name">StopWordFilterWrapper</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token operator">&gt;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">fn</span> <span class="token function-definition function">transform</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token punctuation">:</span> <span class="token class-name">Tokenizer</span><span class="token operator">&gt;</span><span class="token punctuation">(</span><span class="token keyword">self</span><span class="token punctuation">,</span> tokenizer<span class="token punctuation">:</span> <span class="token class-name">T</span><span class="token punctuation">)</span> <span class="token punctuation">-&gt;</span> <span class="token class-name">StopWordFilterWrapper</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token class-name">StopWordFilterWrapper</span> <span class="token punctuation">{</span></span>
<span class="line">            words<span class="token punctuation">:</span> <span class="token keyword">self</span><span class="token punctuation">.</span>words<span class="token punctuation">,</span></span>
<span class="line">            inner<span class="token punctuation">:</span> tokenizer<span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>transform()</code> 做的事情很简单：把自身携带的停用词集合和上游 Tokenizer 一起打包进 <code>StopWordFilterWrapper</code>。这个 Wrapper 自己也实现了 <code>Tokenizer</code>：</p><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token attribute attr-name">#[derive(Clone)]</span></span>
<span class="line"><span class="token keyword">pub</span> <span class="token keyword">struct</span> <span class="token type-definition class-name">StopWordFilterWrapper</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">    words<span class="token punctuation">:</span> <span class="token class-name">Arc</span><span class="token operator">&lt;</span><span class="token class-name">FxHashSet</span><span class="token operator">&lt;</span><span class="token class-name">String</span><span class="token operator">&gt;&gt;</span><span class="token punctuation">,</span></span>
<span class="line">    inner<span class="token punctuation">:</span> <span class="token class-name">T</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">impl</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token punctuation">:</span> <span class="token class-name">Tokenizer</span><span class="token operator">&gt;</span> <span class="token class-name">Tokenizer</span> <span class="token keyword">for</span> <span class="token class-name">StopWordFilterWrapper</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">type</span> <span class="token type-definition class-name">TokenStream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span> <span class="token operator">=</span> <span class="token class-name">StopWordFilterStream</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token punctuation">::</span><span class="token class-name">TokenStream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;&gt;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">fn</span> <span class="token function-definition function">token_stream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span><span class="token punctuation">(</span><span class="token operator">&amp;</span><span class="token lifetime-annotation symbol">&#39;a</span> <span class="token keyword">mut</span> <span class="token keyword">self</span><span class="token punctuation">,</span> text<span class="token punctuation">:</span> <span class="token operator">&amp;</span><span class="token lifetime-annotation symbol">&#39;a</span> <span class="token keyword">str</span><span class="token punctuation">)</span> <span class="token punctuation">-&gt;</span> <span class="token keyword">Self</span><span class="token punctuation">::</span><span class="token class-name">TokenStream</span><span class="token operator">&lt;</span><span class="token lifetime-annotation symbol">&#39;a</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token class-name">StopWordFilterStream</span> <span class="token punctuation">{</span></span>
<span class="line">            words<span class="token punctuation">:</span> <span class="token keyword">self</span><span class="token punctuation">.</span>words<span class="token punctuation">.</span><span class="token function">clone</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">            tail<span class="token punctuation">:</span> <span class="token keyword">self</span><span class="token punctuation">.</span>inner<span class="token punctuation">.</span><span class="token function">token_stream</span><span class="token punctuation">(</span>text<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里的关键在 <code>token_stream()</code>：它先调用上游的 <code>inner.token_stream(text)</code> 拿到原始 token 流，再把这条流包进 <code>StopWordFilterStream</code>。这就是装饰器的嵌套方式：外层调用内层，内层继续调用自己的内层，一层层把 token 流串起来。</p><p>最后看 <code>StopWordFilterStream</code> 如何实现 <code>TokenStream</code>。核心仍然在 <code>advance()</code>：</p><div class="language-rust line-numbers-mode" data-highlighter="prismjs" data-ext="rs"><pre><code class="language-rust"><span class="line"><span class="token keyword">impl</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token punctuation">:</span> <span class="token class-name">TokenStream</span><span class="token operator">&gt;</span> <span class="token class-name">TokenStream</span> <span class="token keyword">for</span> <span class="token class-name">StopWordFilterStream</span><span class="token operator">&lt;</span><span class="token class-name">T</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">fn</span> <span class="token function-definition function">advance</span><span class="token punctuation">(</span><span class="token operator">&amp;</span><span class="token keyword">mut</span> <span class="token keyword">self</span><span class="token punctuation">)</span> <span class="token punctuation">-&gt;</span> <span class="token keyword">bool</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">while</span> <span class="token keyword">self</span><span class="token punctuation">.</span>tail<span class="token punctuation">.</span><span class="token function">advance</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">if</span> <span class="token operator">!</span><span class="token keyword">self</span><span class="token punctuation">.</span>words<span class="token punctuation">.</span><span class="token function">contains</span><span class="token punctuation">(</span><span class="token operator">&amp;</span><span class="token keyword">self</span><span class="token punctuation">.</span>tail<span class="token punctuation">.</span><span class="token function">token</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>text<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">                <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token punctuation">}</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">        <span class="token boolean">false</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token comment">// ...</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>每次调用 <code>advance()</code> 时，它会不断推进上游 token 流，直到遇到一个不在停用词集合中的 token 才返回 <code>true</code>。如果上游已经耗尽，就返回 <code>false</code>。</p><p>被过滤掉的 token 不会出现在下游，但它原本占据的位置不会被重排。因为 <code>position</code> 已经由上游 Tokenizer 递增设置，<code>StopWordFilter</code> 并不修改它，所以剩下的 token position 可能会出现跳跃，比如 <code>0, 1, 3</code>。这个细节对短语查询很重要：position 间距可以告诉搜索引擎，中间有词被跳过。</p><h3 id="tokenfilter-的模式" tabindex="-1"><a class="header-anchor" href="#tokenfilter-的模式"><span>TokenFilter 的模式</span></a></h3><p>从 Tantivy 内置的 TokenFilter 可以归纳出三类实现模式：</p><ul><li><strong>变换型</strong>：修改每个 token，但不改变 token 数量。比如 <code>LowerCaser</code> 把文本转成小写，<code>Stemmer</code> 把文本替换成词干。它们的 <code>advance()</code> 通常是调用一次上游 <code>advance()</code>，然后修改 <code>token_mut().text</code>，一进一出。</li><li><strong>过滤型</strong>：根据条件跳过某些 token。比如 <code>StopWordFilter</code> 跳过停用词，<code>AlphaNumOnlyFilter</code> 跳过非字母数字的 token，<code>RemoveLongFilter</code> 跳过超长 token。它们的 <code>advance()</code> 会在循环中反复调用上游 <code>advance()</code>，直到找到一个满足条件的 token。</li><li><strong>扩展型</strong>：把一个 token 展开成多个 token。比如同义词扩展可以把 &quot;quick&quot; 同时产出为 &quot;quick&quot; 和 &quot;fast&quot;。实现上通常会在 Filter 内部维护一个缓冲区：一次上游 <code>advance()</code> 产生多个候选 token，后续调用再从缓冲区里依次返回。扩展出的 token 可以共享相同的 <code>position</code>，表示它们处在同一个位置。Tantivy 内置没有这类 TokenFilter，但接口本身可以支持。</li></ul><h2 id="内置实现与社区扩展" tabindex="-1"><a class="header-anchor" href="#内置实现与社区扩展"><span>内置实现与社区扩展</span></a></h2><h3 id="内置-tokenizer" tabindex="-1"><a class="header-anchor" href="#内置-tokenizer"><span>内置 Tokenizer</span></a></h3><p>Tantivy 内置的 Tokenizer 覆盖了一些最常见的场景：</p><table><thead><tr><th>类型</th><th>行为</th></tr></thead><tbody><tr><td><code>SimpleTokenizer</code></td><td>按非字母数字字符（<code>!char.is_alphanumeric()</code>）分割，去掉标点</td></tr><tr><td><code>RawTokenizer</code></td><td>不分词，整段文本作为单个 token</td></tr><tr><td><code>WhitespaceTokenizer</code></td><td>按 ASCII 空白字符分割，保留标点</td></tr><tr><td><code>NgramTokenizer</code></td><td>将文本切为指定长度范围的 N-gram</td></tr><tr><td><code>RegexTokenizer</code></td><td>按正则表达式匹配切分</td></tr><tr><td><code>FacetTokenizer</code></td><td>按 <code>/</code> 切分面搜索路径（如 <code>/electronics/phones</code>）</td></tr></tbody></table><h3 id="内置-tokenfilter" tabindex="-1"><a class="header-anchor" href="#内置-tokenfilter"><span>内置 TokenFilter</span></a></h3><p>Filter 则更多是对 token 做后处理：</p><table><thead><tr><th>类型</th><th>行为</th><th>模式</th></tr></thead><tbody><tr><td><code>LowerCaser</code></td><td>将 token 文本转为小写</td><td>变换型</td></tr><tr><td><code>RemoveLongFilter</code></td><td>去掉超过指定字节长度的 token</td><td>过滤型</td></tr><tr><td><code>Stemmer</code></td><td>词干提取，支持 18 种语言</td><td>变换型</td></tr><tr><td><code>StopWordFilter</code></td><td>过滤停用词</td><td>过滤型</td></tr><tr><td><code>AlphaNumOnlyFilter</code></td><td>只保留纯字母数字的 token</td><td>过滤型</td></tr><tr><td><code>AsciiFoldingFilter</code></td><td>将 Unicode 字符映射为 ASCII 等价物（如 é → e）</td><td>变换型</td></tr><tr><td><code>SplitCompoundWords</code></td><td>基于词典拆分复合词（如德语）</td><td>变换型</td></tr></tbody></table><h3 id="社区第三方扩展" tabindex="-1"><a class="header-anchor" href="#社区第三方扩展"><span>社区第三方扩展</span></a></h3><p>由于 Tantivy 把核心接口抽到了独立的 <code>tantivy-tokenizer-api</code> crate 中，第三方可以只依赖这层 API 实现自己的分词器，不需要依赖完整的 tantivy。社区里已经有一些现成实现：</p><ul><li><a href="https://github.com/jiegec/tantivy-jieba" target="_blank" rel="noopener noreferrer">tantivy-jieba</a>：基于结巴分词的中文 Tokenizer，是比较常见的中文分词方案。</li><li><a href="https://github.com/DCjanus/cang-jie" target="_blank" rel="noopener noreferrer">cang-jie</a>：基于 CEDICT 词典的中文 Tokenizer。</li></ul><p>对于更特化的需求，比如拼音展开、同义词扩展，也可以通过自定义 <code>TokenFilter</code> 实现：在 <code>advance()</code> 中把一个 token 转换或展开成多个 token。这样不需要修改基础 Tokenizer，只要在流水线末尾追加新的 filter 即可。</p><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料"><span>参考资料</span></a></h2><ul><li><a href="https://github.com/quickwit-oss/tantivy" target="_blank" rel="noopener noreferrer">Tantivy GitHub Repository</a></li><li><a href="https://github.com/quickwit-oss/tantivy/tree/main/tokenizer-api" target="_blank" rel="noopener noreferrer">tantivy-tokenizer-api Crate</a></li></ul>`,78)])])}const i=s(p,[["render",o]]),r=JSON.parse('{"path":"/notes/Tantivy/Tantivy%20Tokenizer.html","title":"Tantivy - Tokenizer","lang":"en-US","frontmatter":{},"git":{},"filePathRelative":"notes/Tantivy/Tantivy Tokenizer.md"}');export{i as comp,r as data};
